/**
 * Generic resource list page with per-resource analysis drawer.
 */
import React, { useContext, useState } from 'react';
import { useQuery } from '@tanstack/react-query';
import { RefreshCw, Search } from 'lucide-react';
import { AppCtx } from '../App';
import { fetchResources } from '../api/azure';
import PageHeader from '../components/PageHeader';
import AssetIcon from '../components/AssetIcon';
import SyncButton from '../components/SyncButton';
import FetchFromAzureButton from '../components/FetchFromAzureButton';
import AdminOnly from '../components/AdminOnly';
import ActionMessage from '../components/ActionMessage';
import FindingsBadge from '../components/FindingsBadge';
import ResourceInsightDrawer from '../components/ResourceInsightDrawer';
import useResourceSync from '../hooks/useResourceSync';
import useResourceSource from '../hooks/useResourceSource';
import useFindingsIndex from '../hooks/useFindingsIndex';
import { getColumnConfig } from '../config/resourceColumnConfig';
import {
  LoadingState, SubscriptionRequired, EmptyState, QueryErrorState,
} from '../components/QueryStates';
import { iconForRow } from '../config/assetIcons';
import { toDisplayText } from '../utils/formatDisplay';
import { formatCurrency } from '../utils/format';

function rowValue(row, col) {
  if (col.key === 'findings') return null;
  const val = row[col.key] ?? (col.alt ? row[col.alt] : undefined);
  return val;
}

function resourceId(row) {
  return (row.id || row.resource_id || '').toLowerCase();
}

export default function ResourceList({ title, apiPath, iconSrc, iconKey }) {
  const { subscription, billingCurrency } = useContext(AppCtx);
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState(null);
  const { dataSource, isLive, fetchFromAzure, resetToDatabase, isAdmin } = useResourceSource();
  const pageIcon = iconKey || iconSrc;
  const columnConfig = getColumnConfig(apiPath);
  const currency = billingCurrency || 'CAD';

  const { byResourceId, savingsByResource } = useFindingsIndex(subscription);

  const { data, isLoading, isError, error, refetch, isFetching } = useQuery({
    queryKey: [apiPath, subscription, dataSource],
    queryFn: () => fetchResources(apiPath, { subscription_id: subscription, source: dataSource }),
    enabled: !!subscription,
    staleTime: dataSource === 'db' ? 5 * 60_000 : 0,
  });

  const { sync, syncing, message: syncMsg } = useResourceSync({
    subscription,
    invalidateKeys: [[apiPath, subscription], ['resource-counts', subscription], ['findings-index', subscription]],
  });

  const handleSync = async () => {
    try {
      resetToDatabase();
      await sync();
      await refetch();
    } catch {
      /* syncMsg */
    }
  };

  const handleRefresh = () => {
    resetToDatabase();
    refetch();
  };

  const rows = (data || []).filter((r) => {
    if (!search) return true;
    const q = search.toLowerCase();
    return (
      (r.name || r.resource_name || '').toLowerCase().includes(q)
      || (r.resourceGroup || r.resource_group || '').toLowerCase().includes(q)
      || (r.location || '').toLowerCase().includes(q)
      || toDisplayText(r.sku).toLowerCase().includes(q)
    );
  });

  const cols = columnConfig?.columns || [];
  const findingsCount = rows.reduce((n, r) => n + (byResourceId.get(resourceId(r))?.length || 0), 0);
  const totalSavings = rows.reduce((s, r) => s + (savingsByResource.get(resourceId(r)) || 0), 0);

  const renderCell = (row, col) => {
    if (col.type === 'findings') {
      const rid = resourceId(row);
      const findings = byResourceId.get(rid) || [];
      const savings = savingsByResource.get(rid) || row.analysisSavingsUsd || 0;
      const count = findings.length || row.analysisFindingsCount || 0;
      const displayFindings = findings.length > 0
        ? findings
        : Array.from({ length: count }, (_, i) => ({ id: `db-${i}`, severity: row.analysisTopSeverity || 'MEDIUM' }));
      return (
        <FindingsBadge
          findings={displayFindings}
          savings={savings}
        />
      );
    }

    if (col.type === 'cost') {
      const cost = row.monthlyCostUsd ?? row.monthly_cost_usd ?? 0;
      return cost > 0
        ? <span className="resource-cost">{formatCurrency(cost, { currency })}</span>
        : <span style={{ opacity: 0.35 }}>—</span>;
    }

    if (col.key === 'name' || col.key === 'resource_name') {
      const label = toDisplayText(rowValue(row, col));
      return (
        <span className="icon-inline">
          <AssetIcon iconKey={iconForRow(row, { apiPath, fallback: pageIcon })} size={18} />
          <span className="resource-name">{label}</span>
        </span>
      );
    }

    if (col.type === 'state') {
      const stateText = toDisplayText(rowValue(row, col));
      return (
        <span className={`badge ${
          /running|active|enabled|succeeded|attached/i.test(stateText) ? 'badge-success'
            : /stopped|deallocated|disabled|unattached|unassociated/i.test(stateText) ? 'badge-danger'
            : 'badge-warning'
        }`}>
          {stateText}
        </span>
      );
    }

    const val = rowValue(row, col);
    if (val == null) return <span style={{ opacity: 0.35 }}>—</span>;
    if (typeof val === 'number') return val.toLocaleString();
    if (typeof val === 'boolean') return val ? 'Yes' : 'No';
    const text = toDisplayText(val);
    if (text.length > 60) return `${text.slice(0, 58)}…`;
    return text;
  };

  const selectedFindings = selected
    ? (byResourceId.get(resourceId(selected)) || [])
    : [];

  const sourceLabel = isLive ? 'live from Azure' : 'from database';

  return (
    <div>
      <PageHeader
        title={title}
        iconKey={pageIcon}
        subtitle={
          subscription
            ? `${rows.length} resource${rows.length !== 1 ? 's' : ''} · ${sourceLabel}${findingsCount > 0 ? ` · ${findingsCount} open finding${findingsCount !== 1 ? 's' : ''}` : ''}`
            : 'No subscription selected'
        }
      >
        <div className="page-header-actions">
          <div className="search-field">
            <Search size={13} />
            <input
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              placeholder="Filter…"
            />
          </div>
          <AdminOnly>
            <ActionMessage message={syncMsg} />
          </AdminOnly>
          <AdminOnly>
            <SyncButton onClick={handleSync} syncing={syncing} disabled={!subscription} />
            <FetchFromAzureButton
              onClick={fetchFromAzure}
              loading={isFetching && isLive}
              disabled={!subscription}
              active={isLive}
            />
          </AdminOnly>
          <button type="button" className="btn btn-secondary" onClick={handleRefresh} disabled={isFetching || !subscription}>
            <RefreshCw size={13} className={isFetching ? 'spin' : ''} /> Refresh
          </button>
        </div>
      </PageHeader>

      {subscription && rows.length > 0 && (
        <div className="resource-summary-bar">
          <span>{findingsCount > 0 ? `${findingsCount} resources with open findings` : 'No open findings — run analysis on Dashboard'}</span>
          {totalSavings > 0 && (
            <span className="resource-summary-bar__savings">
              Est. savings: {formatCurrency(totalSavings, { currency, decimals: 0 })}/mo
            </span>
          )}
        </div>
      )}

      {!subscription && <SubscriptionRequired />}

      {subscription && isLoading && <LoadingState message={isLive ? 'Fetching from Azure…' : 'Loading from database…'} />}
      {subscription && isError && <QueryErrorState error={error} onRetry={refetch} />}

      {subscription && !isLoading && !isError && rows.length === 0 && (
        <EmptyState
          iconKey={pageIcon}
          message={
            search
              ? 'No results match your filter.'
              : isAdmin
                ? 'No data in the database. Run Sync from Azure to save inventory, or Fetch from Azure for a live preview.'
                : 'No data in the database yet.'
          }
        >
          {!search && (
            <AdminOnly>
              <div style={{ display: 'flex', gap: 8, justifyContent: 'center', marginTop: '1rem', flexWrap: 'wrap' }}>
                <SyncButton onClick={handleSync} syncing={syncing} disabled={!subscription} className="btn btn-primary" />
                <FetchFromAzureButton onClick={fetchFromAzure} disabled={!subscription} className="btn btn-secondary" />
              </div>
            </AdminOnly>
          )}
        </EmptyState>
      )}

      {subscription && !isLoading && !isError && rows.length > 0 && (
        <div className="card resource-table-card">
          <div className="table-wrap">
            <table className="table resource-table">
              <thead>
                <tr>
                  {cols.map((col) => <th key={col.key}>{col.label}</th>)}
                </tr>
              </thead>
              <tbody>
                {rows.map((row) => (
                  <tr
                    key={row.id || row.resource_id || `${row.name}-${row.location}`}
                    className="resource-table__row"
                    onClick={() => setSelected(row)}
                  >
                    {cols.map((col) => (
                      <td key={col.key}>{renderCell(row, col)}</td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <div className="resource-table-footer">
            {rows.length} record{rows.length !== 1 ? 's' : ''}
            {search && ` (filtered from ${data.length})`}
            {isLive && ' · Live preview — use Sync from Azure to save to the database'}
            {' · '}Click a row for optimization analysis
          </div>
        </div>
      )}

      <ResourceInsightDrawer
        resource={selected}
        findings={selectedFindings}
        onClose={() => setSelected(null)}
        title={title}
        iconKey={pageIcon}
      />
    </div>
  );
}
